class Solution:
    def removeInvalidParentheses(self, s: str) -> List[str]:
        level = {s}
        while True:
            valid = filter(self.is_valid, level)
            if valid:
                return list(valid)
            level = self.next_level(level)

    def is_valid(self, s: str) -> bool:
        stack = []
        for ch in s:
            if ch == '(':
                stack.append(ch)
            elif ch == ')':
                if not stack:
                    return False
                stack.pop()
        return not stack

    def next_level(self, level: Set[str]) -> Set[str]:
        next_level = set()
        for item in level:
            for i in range(len(item)):
                if item[i] in ('(', ')'):
                    next_level.add(item[:i] + item[i+1:])
        return next_level
